{
  "name": "StarQuest - Kids Reward System",
  "description": "A gamified task and reward tracker for children, featuring AI-powered task breakdown and parenting advice to help structure positive reinforcement."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Task {
  id: string;
  title: string;
  points: number;
  icon: string;
  isCompleted: boolean;
  category: 'daily' | 'one-time';
}

export interface Reward {
  id: string;
  title: string;
  cost: number;
  icon: string;
}

export interface LogEntry {
  id: string;
  description: string;
  pointsChange: number;
  timestamp: number;
}

export interface AIAdviceResponse {
  advice: string;
  suggestedTasks?: Array<{ title: string; points: number }>;
}

export enum Tab {
  TASKS = 'TASKS',
  REWARDS = 'REWARDS',
  COACH = 'COACH',
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIAdviceResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const modelName = "gemini-2.5-flash";

export const breakDownTask = async (bigTask: string): Promise<AIAdviceResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: `I have an 8-year-old child. I want to break down the task "${bigTask}" into 3-5 smaller, manageable sub-tasks for them to earn points. Return a JSON object with a list of suggested sub-tasks and point values (1-5 range).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            advice: { type: Type.STRING, description: "A brief encouraging tip for the parent." },
            suggestedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  points: { type: Type.INTEGER },
                }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAdviceResponse;
    }
    throw new Error("No response text");
  } catch (error) {
    console.error("Gemini breakdown error:", error);
    return { advice: "Sorry, I couldn't break that down right now.", suggestedTasks: [] };
  }
};

export const getParentingAdvice = async (query: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: query,
      config: {
        systemInstruction: "You are a warm, expert child psychologist specializing in positive reinforcement and token economies for 8-year-olds. Keep answers concise (under 150 words), practical, and encouraging.",
      }
    });
    return response.text || "I'm having trouble thinking right now.";
  } catch (error) {
    console.error("Gemini advice error:", error);
    return "Something went wrong connecting to the AI coach.";
  }
};

import React, { useState } from 'react';
import { Task } from '../types';
import { CheckCircle2, Circle, Sparkles, Plus, Trash2 } from 'lucide-react';
import { breakDownTask } from '../services/geminiService';

interface TaskListProps {
  tasks: Task[];
  onCompleteTask: (task: Task) => void;
  onAddTask: (task: Task) => void;
  onDeleteTask: (id: string) => void;
}

const TaskList: React.FC<TaskListProps> = ({ tasks, onCompleteTask, onAddTask, onDeleteTask }) => {
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPoints, setNewTaskPoints] = useState(5);
  const [isBreakingDown, setIsBreakingDown] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);

  const handleManualAdd = () => {
    if (!newTaskTitle.trim()) return;
    const task: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      points: newTaskPoints,
      icon: '⭐',
      isCompleted: false,
      category: 'daily'
    };
    onAddTask(task);
    setNewTaskTitle('');
    setShowAddForm(false);
  };

  const handleMagicBreakdown = async () => {
    if (!newTaskTitle.trim()) return;
    setIsBreakingDown(true);
    try {
      const result = await breakDownTask(newTaskTitle);
      if (result.suggestedTasks) {
        result.suggestedTasks.forEach((t, index) => {
          onAddTask({
            id: Date.now().toString() + index,
            title: t.title,
            points: t.points,
            icon: '✨',
            isCompleted: false,
            category: 'one-time'
          });
        });
        setNewTaskTitle('');
        setShowAddForm(false);
      }
    } catch (e) {
      alert("Oops, couldn't use magic breakdown right now.");
    } finally {
      setIsBreakingDown(false);
    }
  };

  return (
    <div className="space-y-6 pb-20">
      {/* Add Task Header */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border-2 border-indigo-100">
        {!showAddForm ? (
          <button 
            onClick={() => setShowAddForm(true)}
            className="w-full py-3 flex items-center justify-center gap-2 text-indigo-600 font-bold bg-indigo-50 hover:bg-indigo-100 rounded-xl transition-colors"
          >
            <Plus size={24} /> Add New Mission
          </button>
        ) : (
          <div className="space-y-3">
             <h3 className="text-lg font-bold text-indigo-800">New Mission</h3>
            <input
              type="text"
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="e.g., Clean Bedroom"
              className="w-full p-3 border-2 border-indigo-100 rounded-xl focus:border-indigo-400 outline-none text-lg"
            />

            <div className="flex items-center gap-4">
               <span className="text-gray-600 font-medium">Points:</span>
               <div className="flex gap-2">
                 {[1, 2, 5, 10].map(p => (
                   <button
                    key={p}
                    onClick={() => setNewTaskPoints(p)}
                    className={`w-10 h-10 rounded-full font-bold ${newTaskPoints === p ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
            </div>

            <div className="flex gap-2 pt-2">
              <button 
                onClick={handleManualAdd}
                disabled={isBreakingDown}
                className="flex-1 bg-indigo-600 text-white py-2 rounded-xl font-bold hover:bg-indigo-700 active:scale-95 transition-transform"
              >
                Add
              </button>
              <button 
                onClick={handleMagicBreakdown}
                disabled={isBreakingDown || !newTaskTitle}
                className="flex-1 bg-gradient-to-r from-purple-500 to-pink-500 text-white py-2 rounded-xl font-bold hover:opacity-90 active:scale-95 transition-transform flex items-center justify-center gap-2"
              >
                {isBreakingDown ? (
                  <span className="animate-spin">✨</span>
                ) : (
                  <>
                    <Sparkles size={18} />
                    Magic Split
                  </>
                )}
              </button>
            </div>
            <button onClick={() => setShowAddForm(false)} className="w-full text-gray-400 text-sm py-1">Cancel</button>
          </div>
        )}
      </div>

      {/* Lists */}
      <div className="space-y-3">
        {tasks.length === 0 && (
          <div className="text-center py-10 text-gray-400">
            <p>No active missions. Add one above!</p>
          </div>
        )}

        {tasks.map((task) => (
          <div 
            key={task.id}
            className={`flex items-center justify-between p-4 rounded-2xl shadow-sm border-2 transition-all ${task.isCompleted ? 'bg-green-50 border-green-200 opacity-70' : 'bg-white border-blue-100 hover:border-blue-300'}`}
          >
            <div className="flex items-center gap-4">
              <button 
                onClick={() => onCompleteTask(task)}
                className={`transition-transform active:scale-90 ${task.isCompleted ? 'text-green-500' : 'text-gray-300 hover:text-blue-500'}`}
              >
                {task.isCompleted ? <CheckCircle2 size={32} /> : <Circle size={32} />}
              </button>
              <div>
                <h4 className={`font-bold text-lg ${task.isCompleted ? 'line-through text-gray-500' : 'text-gray-800'}`}>
                  {task.title}
                </h4>
                <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full font-bold">
                  +{task.points} pts
                </span>
              </div>
            </div>
            <button 
              onClick={() => onDeleteTask(task.id)}
              className="text-gray-300 hover:text-red-400 p-2"
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TaskList;

import React from 'react';
import { Reward } from '../types';
import { Gift, Lock } from 'lucide-react';

interface RewardShopProps {
  rewards: Reward[];
  userPoints: number;
  onRedeem: (reward: Reward) => void;
}

const RewardShop: React.FC<RewardShopProps> = ({ rewards, userPoints, onRedeem }) => {
  return (
    <div className="grid grid-cols-2 gap-4 pb-20">
      {rewards.map((reward) => {
        const canAfford = userPoints >= reward.cost;

        return (
          <div 
            key={reward.id}
            className={`relative flex flex-col p-4 rounded-3xl border-4 text-center transition-all ${canAfford ? 'bg-white border-yellow-400 shadow-md' : 'bg-gray-50 border-gray-200'}`}
          >
            <div className="text-4xl mb-2">{reward.icon}</div>
            <h3 className="font-bold text-gray-800 mb-1 leading-tight">{reward.title}</h3>
            <div className={`font-black text-xl mb-3 ${canAfford ? 'text-yellow-600' : 'text-gray-400'}`}>
              {reward.cost} pts
            </div>

            <button
              onClick={() => canAfford && onRedeem(reward)}
              disabled={!canAfford}
              className={`w-full py-2 rounded-xl font-bold flex items-center justify-center gap-2 ${
                canAfford 
                  ? 'bg-yellow-400 text-yellow-900 hover:bg-yellow-500 active:scale-95 shadow-[0_4px_0_rgb(217,119,6)] active:shadow-none active:translate-y-1' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              {canAfford ? (
                <>
                  Get it!
                </>
              ) : (
                <>
                  <Lock size={16} /> Locked
                </>
              )}
            </button>
          </div>
        );
      })}

      <div className="col-span-2 mt-4 p-4 bg-blue-50 rounded-2xl border-2 border-blue-200 text-center">
        <Gift className="mx-auto text-blue-400 mb-2" size={32} />
        <p className="text-blue-800 font-medium">Keep doing great tasks to unlock more rewards!</p>
      </div>
    </div>
  );
};

export default RewardShop;

import React, { useState, useEffect } from 'react';
import { getParentingAdvice } from '../services/geminiService';
import { Send, User, Bot, Loader2 } from 'lucide-react';

const Coach: React.FC = () => {
  const [messages, setMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: "Hi! I'm your StarQuest Coach. I can help you set fair point values, suggest age-appropriate tasks for an 8-year-old, or help you structure this reward system effectively. What's on your mind?" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  // Initial prompt handling if this is first load
  useEffect(() => {
     // Optional: Auto-load the specific user question context if we wanted to
  }, []);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const advice = await getParentingAdvice(userMsg);

    setMessages(prev => [...prev, { role: 'ai', text: advice }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="bg-emerald-600 p-4 text-white">
        <h2 className="font-bold flex items-center gap-2"><Bot size={20}/> Parent Coach</h2>
        <p className="text-emerald-100 text-xs mt-1">AI-powered advice for your reward system</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-blue-100 text-blue-600' : 'bg-emerald-100 text-emerald-600'}`}>
              {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>
            <div className={`p-3 rounded-2xl max-w-[80%] text-sm leading-relaxed ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-gray-100 text-gray-800 rounded-tl-none'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex gap-3">
             <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center shrink-0"><Bot size={16}/></div>
             <div className="bg-gray-100 p-3 rounded-2xl rounded-tl-none flex items-center">
               <Loader2 className="animate-spin text-gray-400" size={16} />
             </div>
          </div>
        )}
      </div>

      <div className="p-3 border-t bg-gray-50 flex gap-2">
        <input 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Ask for advice..."
          className="flex-1 border rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
        />
        <button 
          onClick={handleSend}
          disabled={loading || !input.trim()}
          className="bg-emerald-600 text-white p-2 rounded-full hover:bg-emerald-700 disabled:opacity-50"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
};

export default Coach;

import React, { useState, useEffect } from 'react';
import { Task, Reward, Tab } from './types';
import TaskList from './components/TaskList';
import RewardShop from './components/RewardShop';
import Coach from './components/Coach';
import { Trophy, CheckSquare, ShoppingBag, MessageCircleQuestion, Star } from 'lucide-react';

const INITIAL_TASKS: Task[] = [
  { id: '1', title: 'Brush Teeth (AM)', points: 2, icon: '🪥', isCompleted: false, category: 'daily' },
  { id: '2', title: 'Read 20 mins', points: 5, icon: '📖', isCompleted: false, category: 'daily' },
  { id: '3', title: 'Put away dishes', points: 3, icon: '🍽️', isCompleted: false, category: 'daily' },
];

const INITIAL_REWARDS: Reward[] = [
  { id: '1', title: 'Small Sticker', cost: 5, icon: '🦄' },
  { id: '2', title: '30m Screen Time', cost: 15, icon: '🎮' },
  { id: '3', title: 'Choose Dinner', cost: 25, icon: '🍕' },
  { id: '4', title: 'New Toy', cost: 100, icon: '🧸' },
];

function App() {
  const [points, setPoints] = useState<number>(0);
  const [tasks, setTasks] = useState<Task[]>(INITIAL_TASKS);
  const [rewards, setRewards] = useState<Reward[]>(INITIAL_REWARDS);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.TASKS);
  const [animatePoints, setAnimatePoints] = useState(false);

  // Load state from local storage on mount
  useEffect(() => {
    const savedPoints = localStorage.getItem('sq_points');
    const savedTasks = localStorage.getItem('sq_tasks');
    if (savedPoints) setPoints(Number(savedPoints));
    if (savedTasks) setTasks(JSON.parse(savedTasks));
  }, []);

  // Save state on change
  useEffect(() => {
    localStorage.setItem('sq_points', points.toString());
    localStorage.setItem('sq_tasks', JSON.stringify(tasks));
  }, [points, tasks]);

  const handleCompleteTask = (task: Task) => {
    if (task.isCompleted) return;

    // Award points
    setPoints(prev => prev + task.points);
    setAnimatePoints(true);
    setTimeout(() => setAnimatePoints(false), 500);

    // Mark complete (or remove if one-time)
    if (task.category === 'one-time') {
      setTasks(prev => prev.filter(t => t.id !== task.id));
    } else {
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, isCompleted: true } : t));
    }
  };

  const handleAddTask = (newTask: Task) => {
    setTasks(prev => [...prev, newTask]);
  };

  const handleDeleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleRedeemReward = (reward: Reward) => {
    if (points >= reward.cost) {
      if (window.confirm(`Spend ${reward.cost} points for "${reward.title}"?`)) {
        setPoints(prev => prev - reward.cost);
      }
    }
  };

  const resetDailyTasks = () => {
    if(window.confirm("Reset all daily tasks?")) {
        setTasks(prev => prev.map(t => t.category === 'daily' ? { ...t, isCompleted: false } : t));
    }
  }

  return (
    <div className="min-h-screen bg-sky-50 max-w-md mx-auto shadow-2xl overflow-hidden relative">
      {/* Header / Stats */}
      <header className="bg-indigo-600 text-white p-6 rounded-b-[40px] shadow-lg z-10 relative">
        <div className="flex justify-between items-center mb-4">
          <h1 className="text-2xl font-black tracking-wide flex items-center gap-2">
            <Trophy className="text-yellow-300" /> StarQuest
          </h1>
          <button onClick={resetDailyTasks} className="text-xs bg-indigo-500 hover:bg-indigo-700 px-3 py-1 rounded-full">
            Reset Day
          </button>
        </div>

        <div className="flex flex-col items-center justify-center py-4">
          <div className={`text-6xl font-black flex items-center gap-2 transition-transform ${animatePoints ? 'scale-125' : ''}`}>
             <span className="text-yellow-300 drop-shadow-md">{points}</span>
             <Star className="text-yellow-300 fill-yellow-300" size={48} />
          </div>
          <p className="text-indigo-200 font-bold mt-2 tracking-wider uppercase text-sm">Total Star Points</p>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="p-6">
        {activeTab === Tab.TASKS && (
          <div className="animate-bounce-short">
             <h2 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                <CheckSquare className="text-indigo-500"/> Today's Missions
             </h2>
             <TaskList 
                tasks={tasks} 
                onCompleteTask={handleCompleteTask} 
                onAddTask={handleAddTask}
                onDeleteTask={handleDeleteTask}
             />
          </div>
        )}

        {activeTab === Tab.REWARDS && (
          <div className="animate-bounce-short">
            <h2 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                <ShoppingBag className="text-pink-500"/> Reward Shop
             </h2>
             <RewardShop 
                rewards={rewards} 
                userPoints={points} 
                onRedeem={handleRedeemReward} 
             />
          </div>
        )}

        {activeTab === Tab.COACH && (
          <div className="animate-bounce-short">
             <Coach />
          </div>
        )}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 px-6 py-4 flex justify-between items-center z-50">
        <button 
          onClick={() => setActiveTab(Tab.TASKS)}
          className={`flex flex-col items-center gap-1 ${activeTab === Tab.TASKS ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <CheckSquare size={28} strokeWidth={activeTab === Tab.TASKS ? 3 : 2} />
          <span className="text-xs font-bold">Missions</span>
        </button>

        <button 
          onClick={() => setActiveTab(Tab.REWARDS)}
          className={`flex flex-col items-center gap-1 ${activeTab === Tab.REWARDS ? 'text-pink-600' : 'text-gray-400'}`}
        >
          <ShoppingBag size={28} strokeWidth={activeTab === Tab.REWARDS ? 3 : 2} />
          <span className="text-xs font-bold">Shop</span>
        </button>

        <button 
          onClick={() => setActiveTab(Tab.COACH)}
          className={`flex flex-col items-center gap-1 ${activeTab === Tab.COACH ? 'text-emerald-600' : 'text-gray-400'}`}
        >
          <MessageCircleQuestion size={28} strokeWidth={activeTab === Tab.COACH ? 3 : 2} />
          <span className="text-xs font-bold">Parent Coach</span>
        </button>
      </nav>
    </div>
  );
}

export default App;

