import { GoogleGenAI, Type } from "@google/genai";
import { AIAdviceResponse, TaskModule } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const modelName = "gemini-2.5-flash";

const moduleNames: Record<TaskModule, string> = {
  chinese: 'Chinese (语文)',
  math: 'Math (数学)',
  english: 'English (英语)',
  sports: 'Sports/PE (体育)',
  general: 'General (通用)'
};

export const breakDownTask = async (bigTask: string, module: TaskModule): Promise<AIAdviceResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: `I have an 8-year-old child. I want to break down the ${moduleNames[module]} task "${bigTask}" into 3-5 smaller, manageable sub-tasks. Return a JSON object with a list of suggested sub-tasks and point values (1-5 range). Make them specific to ${moduleNames[module]} if applicable.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            advice: { type: Type.STRING, description: "A brief encouraging tip for the parent." },
            suggestedTasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  points: { type: Type.INTEGER },
                }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAdviceResponse;
    }
    throw new Error("No response text");
  } catch (error) {
    console.error("Gemini breakdown error:", error);
    return { advice: "Sorry, I couldn't break that down right now.", suggestedTasks: [] };
  }
};

export const getParentingAdvice = async (query: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: query,
      config: {
        systemInstruction: "You are a warm, expert child psychologist specializing in positive reinforcement for an 8-year-old. You are helping a parent manage a point-based reward system that includes Chinese, Math, English, and Sports modules. Keep answers concise, practical, and encouraging.",
      }
    });
    return response.text || "I'm having trouble thinking right now.";
  } catch (error) {
    console.error("Gemini advice error:", error);
    return "Something went wrong connecting to the AI coach.";
  }
};

import React, { useState } from 'react';
import { Task, TaskModule } from '../types';
import { CheckCircle2, Circle, Sparkles, Plus, Trash2, BookOpen, Calculator, Globe, Trophy, ListChecks } from 'lucide-react';
import { breakDownTask } from '../services/geminiService';

interface TaskListProps {
  tasks: Task[];
  onCompleteTask: (task: Task) => void;
  onAddTask: (task: Task) => void;
  onDeleteTask: (id: string) => void;
}

const MODULE_CONFIG: Record<TaskModule, { label: string; icon: React.ReactNode; color: string; bgColor: string; borderColor: string; emoji: string }> = {
  chinese: { label: '语文', icon: <BookOpen size={18} />, color: 'text-rose-600', bgColor: 'bg-rose-50', borderColor: 'border-rose-100', emoji: '🏮' },
  math: { label: '数学', icon: <Calculator size={18} />, color: 'text-blue-600', bgColor: 'bg-blue-50', borderColor: 'border-blue-100', emoji: '📐' },
  english: { label: '英语', icon: <Globe size={18} />, color: 'text-emerald-600', bgColor: 'bg-emerald-50', borderColor: 'border-emerald-100', emoji: '🔤' },
  sports: { label: '体育', icon: <Trophy size={18} />, color: 'text-amber-600', bgColor: 'bg-amber-50', borderColor: 'border-amber-100', emoji: '🏃' },
  general: { label: '通用', icon: <ListChecks size={18} />, color: 'text-indigo-600', bgColor: 'bg-indigo-50', borderColor: 'border-indigo-100', emoji: '⭐' },
};

const TaskList: React.FC<TaskListProps> = ({ tasks, onCompleteTask, onAddTask, onDeleteTask }) => {
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPoints, setNewTaskPoints] = useState(5);
  const [selectedModule, setSelectedModule] = useState<TaskModule>('general');
  const [isBreakingDown, setIsBreakingDown] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [activeFilter, setActiveFilter] = useState<TaskModule | 'all'>('all');

  const handleManualAdd = (category: 'daily' | 'one-time') => {
    if (!newTaskTitle.trim()) return;
    const task: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      points: newTaskPoints,
      icon: MODULE_CONFIG[selectedModule].emoji,
      isCompleted: false,
      category: category,
      module: selectedModule
    };
    onAddTask(task);
    setNewTaskTitle('');
    setShowAddForm(false);
  };

  const handleMagicBreakdown = async () => {
    if (!newTaskTitle.trim()) return;
    setIsBreakingDown(true);
    try {
      const result = await breakDownTask(newTaskTitle, selectedModule);
      if (result.suggestedTasks) {
        result.suggestedTasks.forEach((t, index) => {
          onAddTask({
            id: Date.now().toString() + index,
            title: t.title,
            points: t.points,
            icon: MODULE_CONFIG[selectedModule].emoji,
            isCompleted: false,
            category: 'one-time',
            module: selectedModule
          });
        });
        setNewTaskTitle('');
        setShowAddForm(false);
        setActiveFilter(selectedModule);
      }
    } catch (e) {
      alert("Oops, breakdown failed.");
    } finally {
      setIsBreakingDown(false);
    }
  };

  const filteredTasks = tasks.filter(task => {
    if (activeFilter === 'all') return true;
    return task.module === activeFilter;
  });

  return (
    <div className="space-y-6 pb-20">
      {/* Module Quick Filter */}
      <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
        <button
          onClick={() => setActiveFilter('all')}
          className={`px-4 py-2 rounded-full font-bold whitespace-nowrap transition-all border-2 ${
            activeFilter === 'all' ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-100 text-gray-500'
          }`}
        >
          全部
        </button>
        {(Object.keys(MODULE_CONFIG) as TaskModule[]).map((m) => (
          <button
            key={m}
            onClick={() => setActiveFilter(m)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold whitespace-nowrap transition-all border-2 ${
              activeFilter === m 
                ? `${MODULE_CONFIG[m].bgColor} ${MODULE_CONFIG[m].borderColor} ${MODULE_CONFIG[m].color} shadow-md` 
                : 'bg-white border-gray-100 text-gray-400'
            }`}
          >
            {MODULE_CONFIG[m].icon} {MODULE_CONFIG[m].label}
          </button>
        ))}
      </div>

      {/* Add Task Form */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border-2 border-indigo-50">
        {!showAddForm ? (
          <button 
            onClick={() => setShowAddForm(true)}
            className="w-full py-3 flex items-center justify-center gap-2 text-indigo-600 font-bold bg-indigo-50 hover:bg-indigo-100 rounded-xl transition-colors"
          >
            <Plus size={24} /> 新增任务任务模块
          </button>
        ) : (
          <div className="space-y-4">
             <div className="flex justify-between items-center">
                <h3 className="text-lg font-bold text-gray-800">设置新任务</h3>
                <button onClick={() => setShowAddForm(false)} className="text-gray-400">取消</button>
             </div>

             {/* Module Selector in Form */}
             <div className="grid grid-cols-5 gap-1">
                {(Object.keys(MODULE_CONFIG) as TaskModule[]).map((m) => (
                  <button
                    key={m}
                    onClick={() => setSelectedModule(m)}
                    className={`flex flex-col items-center p-2 rounded-xl border-2 transition-all ${
                      selectedModule === m 
                        ? `${MODULE_CONFIG[m].bgColor} ${MODULE_CONFIG[m].borderColor} ${MODULE_CONFIG[m].color}` 
                        : 'border-transparent text-gray-300'
                    }`}
                  >
                    {MODULE_CONFIG[m].icon}
                    <span className="text-[10px] mt-1 font-bold">{MODULE_CONFIG[m].label}</span>
                  </button>
                ))}
             </div>

            <input
              type="text"
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="输入任务名称..."
              className="w-full p-3 border-2 border-gray-100 rounded-xl focus:border-indigo-400 outline-none"
            />

            <div className="flex items-center justify-between">
               <span className="text-sm font-bold text-gray-500">奖励星数:</span>
               <div className="flex gap-1">
                 {[1, 2, 5, 10].map(p => (
                   <button
                    key={p}
                    onClick={() => setNewTaskPoints(p)}
                    className={`w-9 h-9 rounded-lg font-black ${newTaskPoints === p ? 'bg-indigo-600 text-white shadow-inner' : 'bg-gray-100 text-gray-400'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
            </div>

            <div className="flex gap-2">
              <button 
                onClick={() => handleManualAdd('daily')}
                disabled={isBreakingDown}
                className="flex-1 bg-indigo-600 text-white py-2 rounded-xl font-bold shadow-lg"
              >
                设为日常
              </button>
              <button 
                onClick={handleMagicBreakdown}
                disabled={isBreakingDown || !newTaskTitle}
                className="flex-1 bg-gradient-to-r from-purple-500 to-indigo-500 text-white py-2 rounded-xl font-bold flex items-center justify-center gap-2"
              >
                {isBreakingDown ? <span className="animate-spin">✨</span> : <><Sparkles size={16} /> AI拆解</>}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Task List Rendering */}
      <div className="space-y-3">
        {filteredTasks.length === 0 && (
          <div className="text-center py-12">
            <div className="bg-gray-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300">
               <ListChecks size={32} />
            </div>
            <p className="text-gray-400 font-medium">当前模块下没有任务哦</p>
          </div>
        )}

        {filteredTasks.map((task) => {
          const config = MODULE_CONFIG[task.module];
          return (
            <div 
              key={task.id}
              className={`flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${
                task.isCompleted 
                  ? 'bg-gray-50 border-gray-100 opacity-60' 
                  : `bg-white ${config.borderColor} shadow-sm`
              }`}
            >
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => onCompleteTask(task)}
                  className={`transition-transform active:scale-90 ${task.isCompleted ? 'text-green-500' : 'text-gray-200'}`}
                >
                  <CheckCircle2 size={36} strokeWidth={task.isCompleted ? 2.5 : 2} />
                </button>
                <div>
                  <div className="flex items-center gap-2">
                    <span className="text-xl">{task.icon}</span>
                    <h4 className={`font-bold text-gray-800 ${task.isCompleted ? 'line-through text-gray-400' : ''}`}>
                      {task.title}
                    </h4>
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-[10px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded ${config.bgColor} ${config.color}`}>
                      {config.label}
                    </span>
                    <span className="text-xs font-bold text-yellow-600 bg-yellow-50 px-2 rounded-full">
                      +{task.points} 星星
                    </span>
                  </div>
                </div>
              </div>
              <button onClick={() => onDeleteTask(task.id)} className="text-gray-200 hover:text-red-400 transition-colors p-2">
                <Trash2 size={18} />
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default TaskList;

import React, { useState, useEffect } from 'react';
import { Task, Reward, Tab } from './types';
import TaskList from './components/TaskList';
import RewardShop from './components/RewardShop';
import Coach from './components/Coach';
import { Trophy, CheckSquare, ShoppingBag, MessageCircleQuestion, Star, Sparkles } from 'lucide-react';

const INITIAL_TASKS: Task[] = [
  { id: '1', title: '背诵古诗一首', points: 5, icon: '🏮', isCompleted: false, category: 'daily', module: 'chinese' },
  { id: '2', title: '口算练习 20 道', points: 5, icon: '📐', isCompleted: false, category: 'daily', module: 'math' },
  { id: '3', title: '英语绘本阅读', points: 5, icon: '🔤', isCompleted: false, category: 'daily', module: 'english' },
  { id: '4', title: '跳绳 500 下', points: 5, icon: '🏃', isCompleted: false, category: 'daily', module: 'sports' },
];

const INITIAL_REWARDS: Reward[] = [
  { id: '1', title: '小礼品 (文具/贴纸)', cost: 5, icon: '🎁' },
  { id: '2', title: '看电视 30 分钟', cost: 15, icon: '📺' },
  { id: '3', title: '周末吃大餐', cost: 50, icon: '🍕' },
  { id: '4', title: '心仪玩具一个', cost: 100, icon: '🧸' },
];

function App() {
  const [points, setPoints] = useState<number>(0);
  const [tasks, setTasks] = useState<Task[]>(INITIAL_TASKS);
  const [rewards, setRewards] = useState<Reward[]>(INITIAL_REWARDS);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.TASKS);
  const [animatePoints, setAnimatePoints] = useState(false);

  useEffect(() => {
    const savedPoints = localStorage.getItem('sq_points_v2');
    const savedTasks = localStorage.getItem('sq_tasks_v2');
    if (savedPoints) setPoints(Number(savedPoints));
    if (savedTasks) setTasks(JSON.parse(savedTasks));
  }, []);

  useEffect(() => {
    localStorage.setItem('sq_points_v2', points.toString());
    localStorage.setItem('sq_tasks_v2', JSON.stringify(tasks));
  }, [points, tasks]);

  const handleCompleteTask = (task: Task) => {
    if (task.isCompleted) return;
    setPoints(prev => prev + task.points);
    setAnimatePoints(true);
    setTimeout(() => setAnimatePoints(false), 600);
    if (task.category === 'one-time') {
      setTasks(prev => prev.filter(t => t.id !== task.id));
    } else {
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, isCompleted: true } : t));
    }
  };

  const handleAddTask = (newTask: Task) => setTasks(prev => [newTask, ...prev]);
  const handleDeleteTask = (id: string) => setTasks(prev => prev.filter(t => t.id !== id));

  const handleRedeemReward = (reward: Reward) => {
    if (points >= reward.cost) {
      if (window.confirm(`确认兑换 "${reward.title}" 吗？将消耗 ${reward.cost} 星星。`)) {
        setPoints(prev => prev - reward.cost);
      }
    }
  };

  const resetDailyTasks = () => {
    if(window.confirm("确定要重置所有日常任务吗？")) {
        setTasks(prev => prev.map(t => t.category === 'daily' ? { ...t, isCompleted: false } : t));
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 max-w-md mx-auto shadow-2xl overflow-hidden flex flex-col relative pb-20">
      {/* Dynamic Header */}
      <header className="bg-gradient-to-br from-indigo-600 to-violet-700 text-white p-6 rounded-b-[48px] shadow-xl relative z-10">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-black tracking-tight flex items-center gap-2">
            <Sparkles className="text-yellow-300 fill-yellow-300" size={24} /> StarQuest
          </h1>
          <button onClick={resetDailyTasks} className="text-[10px] bg-white/20 backdrop-blur-md px-3 py-1.5 rounded-full font-bold uppercase tracking-wider">
            新的一天
          </button>
        </div>

        <div className="flex flex-col items-center py-2">
          <div className={`relative transition-transform duration-300 ${animatePoints ? 'scale-125' : 'scale-100'}`}>
             <div className="text-7xl font-black text-yellow-300 drop-shadow-[0_4px_4px_rgba(0,0,0,0.25)] flex items-center gap-1">
                {points}
                <Star className="fill-yellow-300" size={40} />
             </div>
             {animatePoints && (
               <div className="absolute -top-4 -right-4 animate-ping">
                 <Star className="text-yellow-200 fill-yellow-200" size={24} />
               </div>
             )}
          </div>
          <p className="text-indigo-100 font-bold mt-2 tracking-widest text-xs uppercase">当前累积星星</p>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 pt-8">
        {activeTab === Tab.TASKS && (
          <div className="space-y-4">
             <div className="flex items-center justify-between">
                <h2 className="text-xl font-black text-slate-800">任务面板</h2>
                <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Modules V2.0</div>
             </div>
             <TaskList 
                tasks={tasks} 
                onCompleteTask={handleCompleteTask} 
                onAddTask={handleAddTask}
                onDeleteTask={handleDeleteTask}
             />
          </div>
        )}

        {activeTab === Tab.REWARDS && (
          <div className="animate-bounce-short">
            <h2 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2">
                <ShoppingBag className="text-pink-500"/> 星星小铺
             </h2>
             <RewardShop 
                rewards={rewards} 
                userPoints={points} 
                onRedeem={handleRedeemReward} 
             />
          </div>
        )}

        {activeTab === Tab.COACH && (
          <div className="h-full">
             <Coach />
          </div>
        )}
      </main>

      {/* Modern Tab Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/80 backdrop-blur-lg border-t border-slate-100 px-8 py-4 flex justify-between items-center z-50 rounded-t-3xl">
        <button 
          onClick={() => setActiveTab(Tab.TASKS)}
