import React, { useState, useEffect } from 'react';
import { Task, Reward, Tab } from './types';
import TaskList from './components/TaskList';
import RewardShop from './components/RewardShop';
import Coach from './components/Coach';
import { Trophy, CheckSquare, ShoppingBag, MessageCircleQuestion, Star, Sparkles, History } from 'lucide-react';

const INITIAL_TASKS: Task[] = [
  { id: '1', title: '背诵古诗一首', points: 5, icon: '🏮', isCompleted: false, category: 'daily', module: 'chinese' },
  { id: '2', title: '口算练习 20 道', points: 5, icon: '📐', isCompleted: false, category: 'daily', module: 'math' },
  { id: '3', title: '英语绘本阅读', points: 5, icon: '🔤', isCompleted: false, category: 'daily', module: 'english' },
  { id: '4', title: '跳绳 500 下', points: 5, icon: '🏃', isCompleted: false, category: 'daily', module: 'sports' },
];

const INITIAL_REWARDS: Reward[] = [
  { id: '1', title: '小礼品 (文具/贴纸)', cost: 5, icon: '🎁' },
  { id: '2', title: '看电视 30 分钟', cost: 15, icon: '📺' },
  { id: '3', title: '周末吃大餐', cost: 50, icon: '🍕' },
  { id: '4', title: '心仪玩具一个', cost: 100, icon: '🧸' },
];

function App() {
  const [points, setPoints] = useState<number>(0);
  const [lifetimePoints, setLifetimePoints] = useState<number>(0);
  const [tasks, setTasks] = useState<Task[]>(INITIAL_TASKS);
  const [rewards, setRewards] = useState<Reward[]>(INITIAL_REWARDS);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.TASKS);
  const [animatePoints, setAnimatePoints] = useState(false);

  // Load Data
  useEffect(() => {
    const savedPoints = localStorage.getItem('sq_points_v3');
    const savedLifetime = localStorage.getItem('sq_lifetime_v3');
    const savedTasks = localStorage.getItem('sq_tasks_v3');

    if (savedPoints) setPoints(Number(savedPoints));
    if (savedLifetime) setLifetimePoints(Number(savedLifetime));
    if (savedTasks) {
      const parsedTasks = JSON.parse(savedTasks);
      // Ensure we don't lose initial tasks if user cleared everything
      setTasks(parsedTasks.length > 0 ? parsedTasks : INITIAL_TASKS);
    }
  }, []);

  // Save Data
  useEffect(() => {
    localStorage.setItem('sq_points_v3', points.toString());
    localStorage.setItem('sq_lifetime_v3', lifetimePoints.toString());
    localStorage.setItem('sq_tasks_v3', JSON.stringify(tasks));
  }, [points, lifetimePoints, tasks]);

  const handleCompleteTask = (task: Task) => {
    if (task.isCompleted) return;

    // Increment both current spendable points and lifetime accumulation
    setPoints(prev => prev + task.points);
    setLifetimePoints(prev => prev + task.points);

    setAnimatePoints(true);
    setTimeout(() => setAnimatePoints(false), 600);

    if (task.category === 'one-time') {
      // For one-time tasks, we mark as completed but keep it in list for a while
      // or we can remove it. Let's keep it visible but checked.
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, isCompleted: true } : t));
    } else {
      // For daily tasks, just mark completed
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, isCompleted: true } : t));
    }
  };

  const handleAddTask = (newTask: Task) => setTasks(prev => [newTask, ...prev]);
  const handleDeleteTask = (id: string) => {
    if(window.confirm("确定要删除这个任务吗？")) {
        setTasks(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleRedeemReward = (reward: Reward) => {
    if (points >= reward.cost) {
      if (window.confirm(`确认兑换 "${reward.title}" 吗？将消耗 ${reward.cost} 星星。`)) {
        setPoints(prev => prev - reward.cost);
        // Lifetime points remain untouched!
      }
    }
  };

  const resetDailyTasks = () => {
    // Only reset the 'isCompleted' status of 'daily' tasks.
    // Do NOT touch points. Do NOT touch task definitions.
    if(window.confirm("开启新的一天？\n(日常任务将重置为待完成，你的星星会继续累积状态)")) {
        setTasks(prev => prev.map(t => {
            // Daily tasks get reset, one-time tasks that are completed stay completed (or could be filtered out)
            if (t.category === 'daily') {
                return { ...t, isCompleted: false };
            }
            return t;
        }));
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 max-w-md mx-auto shadow-2xl overflow-hidden flex flex-col relative pb-20">
      {/* Dynamic Header */}
      <header className="bg-gradient-to-br from-indigo-600 to-violet-700 text-white p-6 rounded-b-[48px] shadow-xl relative z-10">
        <div className="flex justify-between items-center mb-4">
          <div className="flex items-center gap-2">
            <div className="bg-white/20 p-2 rounded-xl backdrop-blur-md">
                <Trophy className="text-yellow-300" size={20} />
            </div>
            <div>
                <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-tighter">荣誉累计</p>
                <p className="text-sm font-black">{lifetimePoints} 星</p>
            </div>
          </div>
          <button 
            onClick={resetDailyTasks} 
            className="flex items-center gap-1.5 text-[11px] bg-yellow-400 text-indigo-900 px-4 py-2 rounded-full font-black shadow-lg active:scale-95 transition-transform"
          >
            <History size={14} /> 新的一天
          </button>
        </div>

        <div className="flex flex-col items-center py-4">
          <div className={`relative transition-transform duration-300 ${animatePoints ? 'scale-110' : 'scale-100'}`}>
             <div className="text-7xl font-black text-white drop-shadow-2xl flex items-center gap-1">
                {points}
                <Star className="text-yellow-300 fill-yellow-300" size={44} />
             </div>
             {animatePoints && (
               <div className="absolute -top-4 -right-4 animate-bounce">
                 <Sparkles className="text-yellow-200" size={32} />
               </div>
             )}
          </div>
          <p className="text-indigo-100 font-bold mt-2 tracking-widest text-xs uppercase bg-white/10 px-4 py-1 rounded-full">可用星星余额</p>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 pt-6">
        {activeTab === Tab.TASKS && (
          <div className="space-y-4">
             <div className="flex items-center justify-between px-1">
                <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
                    <CheckSquare className="text-indigo-500" /> 任务清单
                </h2>
                <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Growth Mode</div>
             </div>
             <TaskList 
                tasks={tasks} 
                onCompleteTask={handleCompleteTask} 
                onAddTask={handleAddTask}
                onDeleteTask={handleDeleteTask}
             />
          </div>
        )}

        {activeTab === Tab.REWARDS && (
          <div className="animate-bounce-short">
             <div className="flex items-center justify-between mb-6 px-1">
                <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
                    <ShoppingBag className="text-pink-500"/> 星星小铺
                </h2>
                <span className="text-xs font-bold text-pink-600 bg-pink-50 px-3 py-1 rounded-full">
                    已有 {points} 星
                </span>
             </div>
             <RewardShop 
                rewards={rewards} 
                userPoints={points} 
                onRedeem={handleRedeemReward} 
             />
          </div>
        )}

        {activeTab === Tab.COACH && (
          <div className="h-full">
             <Coach />
          </div>
        )}
      </main>

      {/* Tab Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-slate-100 px-8 py-4 flex justify-between items-center z-50 rounded-t-[32px] shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
        <button 
          onClick={() => setActiveTab(Tab.TASKS)}
          className={`flex flex-col items-center gap-1 transition-all ${activeTab === Tab.TASKS ? 'text-indigo-600 scale-110' : 'text-slate-300'}`}
        >
          <div className={`p-2 rounded-xl ${activeTab === Tab.TASKS ? 'bg-indigo-50' : ''}`}>
            <CheckSquare size={24} strokeWidth={3} />
          </div>
          <span className="text-[10px] font-black uppercase">任务</span>
        </button>

        <button 
          onClick={() => setActiveTab(Tab.REWARDS)}
          className={`flex flex-col items-center gap-1 transition-all ${activeTab === Tab.REWARDS ? 'text-pink-500 scale-110' : 'text-slate-300'}`}
        >
          <div className={`p-2 rounded-xl ${activeTab === Tab.REWARDS ? 'bg-pink-50' : ''}`}>
            <ShoppingBag size={24} strokeWidth={3} />
          </div>
          <span className="text-[10px] font-black uppercase">奖励</span>
        </button>

        <button 
          onClick={() => setActiveTab(Tab.COACH)}
          className={`flex flex-col items-center gap-1 transition-all ${activeTab === Tab.COACH ? 'text-emerald-500 scale-110' : 'text-slate-300'}`}
        >
          <div className={`p-2 rounded-xl ${activeTab === Tab.COACH ? 'bg-emerald-50' : ''}`}>
            <MessageCircleQuestion size={24} strokeWidth={3} />
          </div>
          <span className="text-[10px] font-black uppercase">咨询</span>
        </button>
      </nav>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Task, TaskModule } from '../types';
import { CheckCircle2, Sparkles, Plus, Trash2, BookOpen, Calculator, Globe, Trophy, ListChecks, Calendar, Zap, X } from 'lucide-react';
import { breakDownTask } from '../services/geminiService';

interface TaskListProps {
  tasks: Task[];
  onCompleteTask: (task: Task) => void;
  onAddTask: (task: Task) => void;
  onDeleteTask: (id: string) => void;
}

const MODULE_CONFIG: Record<TaskModule, { label: string; icon: React.ReactNode; color: string; bgColor: string; borderColor: string; emoji: string }> = {
  chinese: { label: '语文', icon: <BookOpen size={18} />, color: 'text-rose-600', bgColor: 'bg-rose-50', borderColor: 'border-rose-100', emoji: '🏮' },
  math: { label: '数学', icon: <Calculator size={18} />, color: 'text-blue-600', bgColor: 'bg-blue-50', borderColor: 'border-blue-100', emoji: '📐' },
  english: { label: '英语', icon: <Globe size={18} />, color: 'text-emerald-600', bgColor: 'bg-emerald-50', borderColor: 'border-emerald-100', emoji: '🔤' },
  sports: { label: '体育', icon: <Trophy size={18} />, color: 'text-amber-600', bgColor: 'bg-amber-50', borderColor: 'border-amber-100', emoji: '🏃' },
  general: { label: '通用', icon: <ListChecks size={18} />, color: 'text-indigo-600', bgColor: 'bg-indigo-50', borderColor: 'border-indigo-100', emoji: '⭐' },
};

const TaskList: React.FC<TaskListProps> = ({ tasks, onCompleteTask, onAddTask, onDeleteTask }) => {
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPoints, setNewTaskPoints] = useState(5);
  const [selectedModule, setSelectedModule] = useState<TaskModule>('general');
  const [taskCategory, setTaskCategory] = useState<'daily' | 'one-time'>('daily');
  const [isBreakingDown, setIsBreakingDown] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [activeFilter, setActiveFilter] = useState<TaskModule | 'all'>('all');

  const handleManualAdd = () => {
    if (!newTaskTitle.trim()) return;
    const task: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      points: newTaskPoints,
      icon: MODULE_CONFIG[selectedModule].emoji,
      isCompleted: false,
      category: taskCategory,
      module: selectedModule
    };
    onAddTask(task);
    setNewTaskTitle('');
    setShowAddForm(false);
  };

  const handleMagicBreakdown = async () => {
    if (!newTaskTitle.trim()) return;
    setIsBreakingDown(true);
    try {
      const result = await breakDownTask(newTaskTitle, selectedModule);
      if (result.suggestedTasks) {
        result.suggestedTasks.forEach((t, index) => {
          onAddTask({
            id: (Date.now() + index).toString(),
            title: t.title,
            points: t.points,
            icon: MODULE_CONFIG[selectedModule].emoji,
            isCompleted: false,
            category: 'one-time',
            module: selectedModule
          });
        });
        setNewTaskTitle('');
        setShowAddForm(false);
        setActiveFilter(selectedModule);
      }
    } catch (e) {
      alert("AI 拆解失败，请稍后再试。");
    } finally {
      setIsBreakingDown(false);
    }
  };

  const filteredTasks = tasks.filter(task => {
    if (activeFilter === 'all') return true;
    return task.module === activeFilter;
  });

  return (
    <div className="space-y-6 pb-20">
      {/* Module Quick Filter */}
      <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar px-1">
        <button
          onClick={() => setActiveFilter('all')}
          className={`px-4 py-2 rounded-full font-bold whitespace-nowrap transition-all border-2 text-sm ${
            activeFilter === 'all' ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-100 text-gray-500'
          }`}
        >
          全部
        </button>
        {(Object.keys(MODULE_CONFIG) as TaskModule[]).map((m) => (
          <button
            key={m}
            onClick={() => setActiveFilter(m)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold whitespace-nowrap transition-all border-2 text-sm ${
              activeFilter === m 
                ? `${MODULE_CONFIG[m].bgColor} ${MODULE_CONFIG[m].borderColor} ${MODULE_CONFIG[m].color} shadow-md` 
                : 'bg-white border-gray-100 text-gray-400'
            }`}
          >
            {MODULE_CONFIG[m].icon} {MODULE_CONFIG[m].label}
          </button>
        ))}
      </div>

      {/* Add Task Form */}
      <div className="bg-white p-4 rounded-3xl shadow-sm border-2 border-indigo-50 mx-1">
        {!showAddForm ? (
          <button 
            onClick={() => setShowAddForm(true)}
            className="w-full py-4 flex items-center justify-center gap-2 text-indigo-600 font-bold bg-indigo-50 hover:bg-indigo-100 rounded-2xl transition-all active:scale-[0.98]"
          >
            <Plus size={24} /> 添加新任务模块
          </button>
        ) : (
          <div className="space-y-4 animate-in fade-in slide-in-from-top-4 duration-300">
             <div className="flex justify-between items-center">
                <h3 className="text-lg font-black text-gray-800">设置任务内容</h3>
                <button onClick={() => setShowAddForm(false)} className="p-1 text-gray-400 hover:text-gray-600">
                  <X size={20} />
                </button>
             </div>

             {/* Module Selector in Form */}
             <div className="grid grid-cols-5 gap-1 bg-gray-50 p-1 rounded-2xl">
                {(Object.keys(MODULE_CONFIG) as TaskModule[]).map((m) => (
                  <button
                    key={m}
                    onClick={() => setSelectedModule(m)}
                    className={`flex flex-col items-center p-2 rounded-xl border-2 transition-all ${
                      selectedModule === m 
                        ? `${MODULE_CONFIG[m].bgColor} ${MODULE_CONFIG[m].borderColor} ${MODULE_CONFIG[m].color}` 
                        : 'border-transparent text-gray-300'
                    }`}
                  >
                    {MODULE_CONFIG[m].icon}
                    <span className="text-[10px] mt-1 font-bold">{MODULE_CONFIG[m].label}</span>
                  </button>
                ))}
             </div>

            <input
              type="text"
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="例如：背诵《咏鹅》、跳绳10分钟"
              className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-indigo-200 focus:bg-white rounded-2xl outline-none transition-all font-medium"
            />

            <div className="flex flex-col gap-3 px-1">
              <div className="flex items-center justify-between">
                 <span className="text-xs font-black text-gray-400 uppercase tracking-widest">任务类型:</span>
                 <div className="flex gap-2 bg-gray-100 p-1 rounded-xl">
                   <button 
                    onClick={() => setTaskCategory('daily')}
                    className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1.5 transition-all ${taskCategory === 'daily' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400'}`}
                   >
                     <Calendar size={12} /> 日常重复
                   </button>
                   <button 
                    onClick={() => setTaskCategory('one-time')}
                    className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1.5 transition-all ${taskCategory === 'one-time' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-400'}`}
                   >
                     <Zap size={12} /> 一次性
                   </button>
                 </div>
              </div>

              <div className="flex items-center justify-between">
                 <span className="text-xs font-black text-gray-400 uppercase tracking-widest">奖励星星:</span>
                 <div className="flex gap-1">
                   {[1, 2, 5, 10].map(p => (
                     <button
                      key={p}
                      onClick={() => setNewTaskPoints(p)}
                      className={`w-10 h-10 rounded-xl font-black transition-all ${newTaskPoints === p ? 'bg-indigo-600 text-white shadow-lg' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
                     >
                       {p}
                     </button>
                   ))}
                 </div>
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button 
                onClick={handleManualAdd}
                disabled={isBreakingDown || !newTaskTitle.trim()}
                className="flex-[1.5] bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-indigo-200 active:scale-95 transition-all disabled:opacity-50"
              >
                直接添加
              </button>
              <button 
                onClick={handleMagicBreakdown}
                disabled={isBreakingDown || !newTaskTitle.trim()}
                className="flex-1 bg-gradient-to-br from-purple-500 to-indigo-600 text-white py-4 rounded-2xl font-black flex items-center justify-center gap-2 shadow-lg shadow-purple-200 active:scale-95 transition-all disabled:opacity-50"
              >
                {isBreakingDown ? <div className="animate-spin text-lg">✨</div> : <><Sparkles size={18} /> AI拆解</>}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Task List Rendering */}
      <div className="space-y-4 px-1">
        {filteredTasks.length === 0 && (
          <div className="text-center py-16 bg-white/50 rounded-3xl border-2 border-dashed border-gray-200">
            <div className="bg-gray-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300">
               <ListChecks size={40} />
            </div>
            <p className="text-gray-400 font-bold">暂时没有任务，快去添加吧！</p>
          </div>
        )}

        {filteredTasks.map((task) => {
          const config = MODULE_CONFIG[task.module];
          return (
            <div 
              key={task.id}
              className={`group flex items-center justify-between p-5 rounded-[2rem] border-2 transition-all duration-300 ${
                task.isCompleted 
                  ? 'bg-slate-50 border-slate-100 opacity-60 scale-95' 
                  : `bg-white ${config.borderColor} shadow-sm hover:shadow-md hover:-translate-y-0.5`
              }`}
            >
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => onCompleteTask(task)}
                  className={`transition-all active:scale-75 flex-shrink-0 ${task.isCompleted ? 'text-emerald-500' : 'text-gray-200 hover:text-indigo-200'}`}
                >
                  <CheckCircle2 size={42} strokeWidth={task.isCompleted ? 2.5 : 2} />
                </button>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 overflow-hidden">
                    <span className="text-2xl flex-shrink-0">{task.icon}</span>
                    <h4 className={`font-bold text-gray-800 truncate text-lg ${task.isCompleted ? 'line-through text-gray-400' : ''}`}>
                      {task.title}
                    </h4>
                  </div>
                  <div className="flex items-center gap-2 mt-2">
                    <span className={`text-[9px] font-black uppercase tracking-tighter px-2 py-0.5 rounded-full ${config.bgColor} ${config.color}`}>
                      {config.label}
                    </span>
                    <span className={`text-[9px] font-black uppercase tracking-tighter px-2 py-0.5 rounded-full ${task.category === 'daily' ? 'bg-indigo-50 text-indigo-500' : 'bg-orange-50 text-orange-500'}`}>
                      {task.category === 'daily' ? '每日重复' : '一次性'}
                    </span>
                    <span className="text-[10px] font-black text-yellow-600 bg-yellow-100/50 px-2 py-0.5 rounded-full">
                      +{task.points} ⭐
                    </span>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => onDeleteTask(task.id)} 
                className="opacity-0 group-hover:opacity-100 text-gray-200 hover:text-rose-500 transition-all p-2 rounded-xl hover:bg-rose-50"
              >
                <Trash2 size={20} />
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default TaskList;

