  /**
   * 彻底修复：重置所有任务状态
   * 采用解构赋值确保对象引用完全更新，并强制更新 Key
   */
  const resetDailyTasks = () => {
    if (window.confirm("确认开启新的一天？\n清单中所有已完成的任务将恢复为“待完成”状态。")) {
