      const resetTasks = tasks.map(t => ({
        ...t,
        isCompleted: false
      }));

      // 2. 更新状态：使用新数组
      setTasks(resetTasks);

      // 3. 增加 Key：强制 React 销毁并重新创建 TaskList，彻底清除 UI 视觉残留
      setDayKey(prev => prev + 1);

      // 4. 视觉反馈
      setAnimatePoints(true);
      setTimeout(() => setAnimatePoints(false), 600);

