        </button>
      </nav>

      <DataSyncModal isOpen={isSyncModalOpen} onClose={() => setIsSyncModalOpen(false)} />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { X, Copy, Check, Download, Upload, Cloud, AlertCircle } from 'lucide-react';

interface DataSyncModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const DataSyncModal: React.FC<DataSyncModalProps> = ({ isOpen, onClose }) => {
  const [activeTab, setActiveTab] = useState<'export' | 'import'>('export');
  const [saveCode, setSaveCode] = useState('');
  const [importCode, setImportCode] = useState('');
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (isOpen && activeTab === 'export') {
      generateSaveCode();
    }
  }, [isOpen, activeTab]);

  const generateSaveCode = () => {
    const data = {
      points: localStorage.getItem('sq_points_v4'),
      lifetime: localStorage.getItem('sq_lifetime_v4'),
      tasks: localStorage.getItem('sq_tasks_v4'),
      timestamp: Date.now()
    };
    const jsonStr = JSON.stringify(data);
    const encoded = btoa(unescape(encodeURIComponent(jsonStr)));
    setSaveCode(encoded);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(saveCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleImport = () => {
    setError('');
    try {
      if (!importCode.trim()) {
        setError('请输入存档代码');
        return;
      }
      const decoded = decodeURIComponent(escape(atob(importCode)));
      const data = JSON.parse(decoded);

      if (data.points === undefined || data.tasks === undefined) {
        throw new Error('存档格式错误');
      }

      if (window.confirm('确认导入存档吗？这将覆盖当前所有进度并刷新页面。')) {
        localStorage.setItem('sq_points_v4', data.points);
        localStorage.setItem('sq_lifetime_v4', data.lifetime || '0');
        localStorage.setItem('sq_tasks_v4', data.tasks);
        window.location.reload();
      }
    } catch (e) {
      setError('无效的存档代码，请检查是否完整复制。');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div 
        className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-4 duration-300"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="bg-indigo-600 p-6 text-white flex justify-between items-center">
          <div className="flex items-center gap-3">
            <Cloud size={24} />
            <h2 className="text-xl font-black">数据同步</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-all">
            <X size={20} />
          </button>
        </div>

        <div className="p-1 flex bg-slate-100 mx-6 mt-6 rounded-2xl">
          <button 
            onClick={() => setActiveTab('export')}
            className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-sm transition-all ${activeTab === 'export' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
          >
            <Download size={16} /> 导出存档
          </button>
          <button 
            onClick={() => setActiveTab('import')}
            className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-sm transition-all ${activeTab === 'import' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
          >
            <Upload size={16} /> 导入存档
          </button>
        </div>

        <div className="p-6">
          {activeTab === 'export' ? (
            <div className="space-y-4">
              <p className="text-sm text-slate-500 font-medium">
                复制下方的代码，可以粘贴到其他设备上恢复你的进度。
              </p>
              <div className="relative group">
                <textarea 
                  readOnly 
                  value={saveCode}
                  className="w-full h-32 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[10px] font-mono break-all focus:outline-none focus:border-indigo-200 transition-all resize-none"
                />
                <div className="absolute inset-0 bg-white/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                  <span className="bg-white px-4 py-2 rounded-full shadow-lg text-indigo-600 font-bold text-xs">
                    存档码已生成
                  </span>
                </div>
              </div>
              <button 
                onClick={handleCopy}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black flex items-center justify-center gap-2 shadow-lg shadow-indigo-100 active:scale-95 transition-all"
              >
                {copied ? <><Check size={18} /> 已复制到剪贴板</> : <><Copy size={18} /> 一键复制存档码</>}
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <p className="text-sm text-slate-500 font-medium">
                粘贴你在其他设备上导出的存档代码。
              </p>
              <textarea 
                value={importCode}
                onChange={(e) => {
                  setImportCode(e.target.value);
                  setError('');
                }}
                placeholder="在此粘贴存档码..."
                className={`w-full h-32 p-4 bg-slate-50 border-2 rounded-2xl text-[10px] font-mono break-all focus:outline-none transition-all resize-none ${error ? 'border-rose-200 bg-rose-50' : 'border-slate-100 focus:border-indigo-200'}`}
              />
              {error && (
                <div className="flex items-center gap-2 text-rose-500 text-xs font-bold animate-in fade-in slide-in-from-left-2">
                  <AlertCircle size={14} /> {error}
                </div>
              )}
              <button 
                onClick={handleImport}
                className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black flex items-center justify-center gap-2 shadow-lg shadow-emerald-100 active:scale-95 transition-all"
              >
                <Check size={18} /> 确认导入并刷新
              </button>
            </div>
          )}
        </div>

        <div className="px-6 pb-6 text-center">
          <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">
            StarQuest Cloud Sync v1.0
          </p>
        </div>
      </div>
    </div>
  );
};

export default DataSyncModal;

import React, { useState, useEffect } from 'react';
import { getParentingAdvice } from '../services/geminiService';
import { Send, User, Bot, Loader2 } from 'lucide-react';

const Coach: React.FC = () => {
  const [messages, setMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: "你好！我是 StarQuest 育儿教练。我可以帮你设定合理的积分值，为 8 岁的孩子建议合适的任务，或者帮你完善这个奖励机制。你想聊聊什么？" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const advice = await getParentingAdvice(userMsg);

    setMessages(prev => [...prev, { role: 'ai', text: advice }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="bg-emerald-600 p-4 text-white">
        <h2 className="font-bold flex items-center gap-2"><Bot size={20}/> 育儿专家建议</h2>
        <p className="text-emerald-100 text-xs mt-1">基于 AI 的奖励机制优化建议</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-blue-100 text-blue-600' : 'bg-emerald-100 text-emerald-600'}`}>
              {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>
            <div className={`p-3 rounded-2xl max-w-[80%] text-sm leading-relaxed ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-gray-100 text-gray-800 rounded-tl-none'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex gap-3">
             <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center shrink-0"><Bot size={16}/></div>
             <div className="bg-gray-100 p-3 rounded-2xl rounded-tl-none flex items-center">
               <Loader2 className="animate-spin text-gray-400" size={16} />
             </div>
          </div>
        )}
      </div>

      <div className="p-3 border-t bg-gray-50 flex gap-2">
        <input 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="问问专家的建议..."
          className="flex-1 border rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
        />
        <button 
          onClick={handleSend}
          disabled={loading || !input.trim()}
          className="bg-emerald-600 text-white p-2 rounded-full hover:bg-emerald-700 disabled:opacity-50"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
};

export default Coach;

import React from 'react';
import { Reward } from '../types';
import { Gift, Lock } from 'lucide-react';

interface RewardShopProps {
  rewards: Reward[];
  userPoints: number;
  onRedeem: (reward: Reward) => void;
}

const RewardShop: React.FC<RewardShopProps> = ({ rewards, userPoints, onRedeem }) => {
  return (
    <div className="grid grid-cols-2 gap-4 pb-20">
      {rewards.map((reward) => {
        const canAfford = userPoints >= reward.cost;

        return (
          <div 
            key={reward.id}
            className={`relative flex flex-col p-4 rounded-3xl border-4 text-center transition-all ${canAfford ? 'bg-white border-yellow-400 shadow-md' : 'bg-gray-50 border-gray-200'}`}
          >
            <div className="text-4xl mb-2">{reward.icon}</div>
            <h3 className="font-bold text-gray-800 mb-1 leading-tight">{reward.title}</h3>
            <div className={`font-black text-xl mb-3 ${canAfford ? 'text-yellow-600' : 'text-gray-400'}`}>
              {reward.cost} 星星
            </div>

            <button
              onClick={() => canAfford && onRedeem(reward)}
              disabled={!canAfford}
              className={`w-full py-2 rounded-xl font-bold flex items-center justify-center gap-2 ${
                canAfford 
                  ? 'bg-yellow-400 text-yellow-900 hover:bg-yellow-500 active:scale-95 shadow-[0_4px_0_rgb(217,119,6)] active:shadow-none active:translate-y-1' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed'
              }`}
            >
              {canAfford ? (
                <>
                  立即兑换!
                </>
              ) : (
                <>
                  <Lock size={16} /> 星星不足
                </>
              )}
            </button>
          </div>
        );
      })}

      <div className="col-span-2 mt-4 p-4 bg-blue-50 rounded-2xl border-2 border-blue-200 text-center">
        <Gift className="mx-auto text-blue-400 mb-2" size={32} />
        <p className="text-blue-800 font-medium">继续努力做任务，解锁更多惊喜奖励！</p>
      </div>
    </div>
  );
};

export default RewardShop;
